 class BlogContext : DbContext
 {
     public DbSet<Blog> Blogs => Set<Blog>();

     protected override void OnModelCreating(ModelBuilder modelBuilder)
     {
         // FIX 1 – Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
         //   Existing documents use "Discriminator"; keep the old JSON property name.
         modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

         // FIX 2 – Id format changed from "Blog|<key>" to just "<key>" in EF Core 9.
         //   Existing documents have id = "Blog|1". Use a value converter to preserve
         //   the old format so reads and writes remain compatible.
         modelBuilder.Entity<Blog>().Property(b => b.Id)
             .HasConversion(
